// G4 — Validação pré-acumulação do PersonaOutput recebido
// SEM require(), SEM $env

const webhookData = $('Webhook Accumulate').first().json;
const result = webhookData.body || webhookData;

const TAGS_VALIDAS = ['AUD', 'GP', 'ARQ', 'DBA', 'DEV', 'QA', 'UX', 'UI', 'SEG', 'CONF', 'LGPD', 'NEG'];
const errors = [];

if (result.schema_version !== 'PersonaOutput-v2') {
  errors.push(`schema_version inválido: '${result.schema_version}' (esperado PersonaOutput-v2)`);
}
if (!TAGS_VALIDAS.includes(result.persona_tag)) {
  errors.push(`persona_tag '${result.persona_tag}' não canônica`);
}
if (typeof result.score !== 'number' || result.score < 0 || result.score > 100) {
  errors.push(`score fora de 0-100: ${result.score}`);
}
if (!result.ocg_contributions || typeof result.ocg_contributions !== 'object') {
  errors.push('ocg_contributions ausente');
} else {
  if (!result.ocg_contributions.individual) errors.push('ocg_contributions.individual ausente');
  if (!result.ocg_contributions.global_delta) errors.push('ocg_contributions.global_delta ausente');
}
if (!result.ingestion_id) errors.push('ingestion_id ausente');

return [{
  json: {
    result,
    valid: errors.length === 0,
    errors,
    ingestion_id: result.ingestion_id || 'unknown',
    persona_tag: result.persona_tag || 'unknown'
  }
}];

// Merge de todos os resultados com pesos por persona
// REGRA DETERMINÍSTICA: CONF.score < 60 → blocked=true
// SEM require(), SEM $env

const input = $input.first().json;
const results = input.all_results || [];

// Pesos por persona — spec v2 §6.4
const PESOS = { CONF: 1.5, SEG: 1.3, LGPD: 1.3, QA: 1.1, AUD: 1.0, ARQ: 1.0, DBA: 1.0, GP: 1.0, NEG: 1.0, DEV: 0.9, UX: 0.8, UI: 0.7 };

let weightedSum = 0;
let totalWeight = 0;
let blocked = false;
let blockingReason = null;
const personasExecuted = [];
const personasFailed = [];
const mergedIndividual = {};
const mergedGlobalDelta = {};
const allFindings = [];
const allRecommendations = [];

for (const r of results) {
  if (r.status === 'failed') {
    personasFailed.push(r.persona_tag);
    continue;
  }
  personasExecuted.push(r.persona_tag);
  const w = PESOS[r.persona_tag] || 1.0;
  weightedSum += r.score * w;
  totalWeight += w;

  // REGRA DETERMINÍSTICA: CONF < 60 → blocked
  if (r.persona_tag === 'CONF' && r.score < 60) {
    blocked = true;
    blockingReason = `CONF: score ${r.score} < 60 (limiar de conformidade)`;
  }
  // Também respeita flag blocking do próprio resultado
  if (r.blocking && !blocked) {
    blocked = true;
    blockingReason = `${r.persona_tag}: ${r.blocking_reason || 'score < 60'}`;
  }

  // Merge OCG
  mergedIndividual[r.persona_tag] = r.ocg_contributions?.individual || {};
  const delta = r.ocg_contributions?.global_delta || {};
  for (const [k, v] of Object.entries(delta)) {
    if (!mergedGlobalDelta[k]) {
      mergedGlobalDelta[k] = v;
    } else if (Array.isArray(v)) {
      mergedGlobalDelta[k] = [...(mergedGlobalDelta[k] || []), ...v];
    }
  }

  allFindings.push(...(r.findings || []).map(f => ({ ...f, source_persona: r.persona_tag })));
  allRecommendations.push(...(r.recommendations || []).map(rec => ({ ...rec, source_persona: r.persona_tag })));
}

const overallScore = totalWeight > 0 ? Math.round(weightedSum / totalWeight) : 0;

const finalResult = {
  ingestion_id: input.ingestion_id,
  project_id: input.project_id,
  status: personasFailed.length > 0 ? 'partial' : 'completed',
  overall_score: overallScore,
  blocked,
  blocking_reason: blockingReason,
  personas_executed: personasExecuted,
  personas_failed: personasFailed,
  ocg_individual: mergedIndividual,
  ocg_global_delta: mergedGlobalDelta,
  consolidated_findings: allFindings,
  consolidated_recommendations: allRecommendations,
  callback_url: input.callback_url,
  execution_summary: {
    total_duration_ms: 0,
    personas_count: personasExecuted.length,
    personas_failed_count: personasFailed.length
  },
  completed_at: new Date().toISOString()
};

return [{ json: finalResult }];
